using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_WithValidPageIndex_SetsPageIndexCorrectly()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };
            int count = 10;
            int pageIndex = 3;
            int pageSize = 3;

            // Act
            var list = new PaginatedList<int>(items, count, pageIndex, pageSize);

            // Assert
            Assert.Equal(3, list.PageIndex);
        }

        [Fact]
        public void Constructor_With10ItemsAndPageSize3_CalculatesTotalPagesAs4()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };
            int count = 10;
            int pageIndex = 1;
            int pageSize = 3;

            // Act
            var list = new PaginatedList<int>(items, count, pageIndex, pageSize);

            // Assert
            Assert.Equal(4, list.TotalPages);
        }

        [Fact]
        public void Constructor_WithItems_AddsItemsToList()
        {
            // Arrange
            var items = new List<int> { 10, 20, 30 };
            int count = 9;
            int pageIndex = 1;
            int pageSize = 3;

            // Act
            var list = new PaginatedList<int>(items, count, pageIndex, pageSize);

            // Assert
            Assert.Equal(3, list.Count);
            Assert.Contains(10, list);
            Assert.Contains(20, list);
            Assert.Contains(30, list);
        }

        [Fact]
        public void HasPreviousPage_OnPage1_ReturnsFalse()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 9, 1, 3);

            // Act
            bool result = list.HasPreviousPage;

            // Assert
            Assert.False(result);
        }

        [Fact]
        public void HasPreviousPage_OnPage2_ReturnsTrue()
        {
            // Arrange
            var items = new List<int> { 4, 5, 6 };
            var list = new PaginatedList<int>(items, 9, 2, 3);

            // Act
            bool result = list.HasPreviousPage;

            // Assert
            Assert.True(result);
        }

        [Fact]
        public void HasNextPage_WhenNotOnLastPage_ReturnsTrue()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 9, 1, 3);

            // Act
            bool result = list.HasNextPage;

            // Assert
            Assert.True(result);
        }

        [Fact]
        public void HasNextPage_OnLastPage_ReturnsFalse()
        {
            // Arrange
            var items = new List<int> { 7, 8, 9 };
            var list = new PaginatedList<int>(items, 9, 3, 3);

            // Act
            bool result = list.HasNextPage;

            // Assert
            Assert.False(result);
        }

        [Fact]
        public void Create_WithQueryable_PaginatesCorrectly()
        {
            // Arrange
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var list = PaginatedList<int>.Create(source, 1, 3);

            // Assert
            Assert.Equal(3, list.Count);
            Assert.Equal(4, list.TotalPages);
            Assert.Equal(1, list.PageIndex);
        }

        [Fact]
        public void Create_Page1_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var list = PaginatedList<int>.Create(source, 1, 3);

            // Assert
            Assert.Equal(new List<int> { 1, 2, 3 }, list.ToList());
        }

        [Fact]
        public void Create_Page2_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var list = PaginatedList<int>.Create(source, 2, 3);

            // Assert
            Assert.Equal(new List<int> { 4, 5, 6 }, list.ToList());
        }

        [Fact]
        public void TotalPages_WhenCountEqualsPageSize_Returns1()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };
            int count = 3;
            int pageSize = 3;

            // Act
            var list = new PaginatedList<int>(items, count, 1, pageSize);

            // Assert
            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void TotalPages_WhenCountIsZero_Returns0()
        {
            // Arrange
            var items = new List<int>();
            int count = 0;
            int pageSize = 3;

            // Act
            var list = new PaginatedList<int>(items, count, 1, pageSize);

            // Assert
            Assert.Equal(0, list.TotalPages);
        }
    }
}

