using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            _context = new SchoolContext(options);
            _controller = new HomeController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_Always_ReturnsViewResult()
        {
            // Act
            var result = _controller.Index();

            // Assert
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_Always_ReturnsViewResultWithEnrollmentDateGroupList()
        {
            // Act
            var result = _controller.About();

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<List<EnrollmentDateGroup>>(viewResult.Model);
        }

        [Fact]
        public void About_WithSeededStudents_ReturnsCorrectStudentCountsGroupedByEnrollmentDate()
        {
            // Arrange
            var date1 = new DateTime(2023, 9, 1);
            var date2 = new DateTime(2024, 1, 15);

            _context.Students.AddRange(
                new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = date1 },
                new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = date1 },
                new Student { LastName = "Brown", FirstMidName = "Bob", EnrollmentDate = date2 }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.About();

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.Equal(2, model.Count);

            var group1 = model.Single(g => g.EnrollmentDate == date1);
            Assert.Equal(2, group1.StudentCount);

            var group2 = model.Single(g => g.EnrollmentDate == date2);
            Assert.Equal(1, group2.StudentCount);
        }

        [Fact]
        public void Contact_Always_ReturnsViewResultWithMessage()
        {
            // Act
            var result = _controller.Contact();

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("Your contact page.", _controller.ViewBag.Message);
        }

        [Fact]
        public void Error_Always_ReturnsViewResult()
        {
            // Act
            var result = _controller.Error();

            // Assert
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_Always_ReturnsViewResultWithMessage()
        {
            // Act
            var result = _controller.Unauthorized();

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

