            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Baker", model[0].LastName);   // 2019
            Assert.Equal("Adams", model[1].LastName);   // 2020
            Assert.Equal("Clark", model[2].LastName);    // 2021
