using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests
    {
        private SchoolContext CreateContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            return new SchoolContext(options);
        }

        private (Department department, Instructor instructor) SeedDepartment(SchoolContext context)
        {
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Parse("2020-01-01")
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var department = new Department
            {
                Name = "Engineering",
                Budget = 100000m,
                StartDate = DateTime.Parse("2021-01-01"),
                InstructorID = instructor.ID,
                Administrator = instructor
            };
            context.Departments.Add(department);
            context.SaveChanges();

            return (department, instructor);
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            // Arrange
            var context = CreateContext();
            var (department, instructor) = SeedDepartment(context);
            var controller = new DepartmentsController(context);

            // Act
            var result = controller.Index();

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Department>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Engineering", model[0].Name);
            Assert.NotNull(model[0].Administrator);
            Assert.Equal("Smith", model[0].Administrator.LastName);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Arrange
            var context = CreateContext();
            var controller = new DepartmentsController(context);

            // Act
            var result = controller.Details(null);

            // Assert
            var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusCodeResult.StatusCode);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            // Arrange
            var context = CreateContext();
            var controller = new DepartmentsController(context);

            // Act
            var result = controller.Details(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            // Arrange
            var context = CreateContext();
            var (department, _) = SeedDepartment(context);
            var controller = new DepartmentsController(context);

            // Act
            var result = controller.Details(department.DepartmentID);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("Engineering", model.Name);
        }

        // --- Create (GET) ---

        [Fact]
        public void Create_Get_ReturnsView()
        {
            // Arrange
            var context = CreateContext();
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = DateTime.Parse("2020-01-01")
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();
            var controller = new DepartmentsController(context);

            // Act
            var result = controller.Create();

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
            var selectList = Assert.IsType<Microsoft.AspNetCore.Mvc.Rendering.SelectList>(controller.ViewBag.InstructorID);
            Assert.Single(selectList);
        }

        // --- Create (POST) ---

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            // Arrange
            var context = CreateContext();
            var controller = new DepartmentsController(context);
            var department = new Department
            {
                Name = "Science",
                Budget = 50000m,
                StartDate = DateTime.Parse("2022-01-01")
            };

            // Act
            var result = controller.Create(department);

            // Assert
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Single(context.Departments);
            Assert.Equal("Science", context.Departments.First().Name);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var context = CreateContext();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                Budget = 50000m,
                StartDate = DateTime.Parse("2022-01-01")
            };

            // Act
            var result = controller.Create(department);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal(department, model);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        // --- Edit (GET) ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Arrange
            var context = CreateContext();
            var controller = new DepartmentsController(context);

            // Act
            var result = controller.Edit(null);

            // Assert
            var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusCodeResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            // Arrange
            var context = CreateContext();
            var controller = new DepartmentsController(context);

            // Act
            var result = controller.Edit(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            // Arrange
            var context = CreateContext();
            var (department, _) = SeedDepartment(context);
            var controller = new DepartmentsController(context);

            // Act
            var result = controller.Edit(department.DepartmentID);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("Engineering", model.Name);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        // --- Edit (POST) ---

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            // Arrange
            var context = CreateContext();
            var (department, _) = SeedDepartment(context);

            // Detach the tracked entity so the Edit POST can attach it
            context.Entry(department).State = EntityState.Detached;

            var controller = new DepartmentsController(context);
            department.Name = "Updated Engineering";

            // Act
            var result = controller.Edit(department);

            // Assert
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            var updated = context.Departments.Find(department.DepartmentID);
            Assert.Equal("Updated Engineering", updated!.Name);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var context = CreateContext();
            var (department, _) = SeedDepartment(context);
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");

            // Act
            var result = controller.Edit(department);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal(department, model);
        }

        // --- Delete (GET) ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Arrange
            var context = CreateContext();
            var controller = new DepartmentsController(context);

