using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests
    {
        private SchoolContext CreateContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            return new SchoolContext(options);
        }

        private CoursesController CreateController(SchoolContext context)
        {
            var mockEnv = new Mock<IWebHostEnvironment>();
            mockEnv.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
            mockEnv.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
            var mockLogger = new Mock<ILogger<CoursesController>>();
            return new CoursesController(context, mockEnv.Object, mockLogger.Object);
        }

        private Department SeedDepartment(SchoolContext context)
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 100000m,
                StartDate = DateTime.Now
            };
            context.Departments.Add(dept);
            context.SaveChanges();
            return dept;
        }

        private Course SeedCourse(SchoolContext context, int departmentId)
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Intro to CS",
                Credits = 3,
                DepartmentID = departmentId
            };
            context.Courses.Add(course);
            context.SaveChanges();
            return course;
        }

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            // Arrange
            var context = CreateContext();
            var dept = SeedDepartment(context);
            SeedCourse(context, dept.DepartmentID);
            var controller = CreateController(context);

            // Act
            var result = controller.Index();

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
            Assert.Single(model);
            Assert.NotNull(model[0].Department);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Arrange
            var context = CreateContext();
            var controller = CreateController(context);

            // Act
            var result = controller.Details(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            // Arrange
            var context = CreateContext();
            var dept = SeedDepartment(context);
            var course = SeedCourse(context, dept.DepartmentID);
            var controller = CreateController(context);

            // Act
            var result = controller.Details(course.CourseID);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(course.CourseID, model.CourseID);
            Assert.NotNull(model.Department);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithNewCourse()
        {
            // Arrange
            var context = CreateContext();
            SeedDepartment(context);
            var controller = CreateController(context);

            // Act
            var result = controller.Create();

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(0, model.CourseID);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            // Arrange
            var context = CreateContext();
            var dept = SeedDepartment(context);
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 2002,
                Title = "Algorithms",
                Credits = 4,
                DepartmentID = dept.DepartmentID
            };

            // Act
            var result = controller.Create(course, null);

            // Assert
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(1, context.Courses.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
