using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests
    {
        private static SchoolContext CreateContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            return new SchoolContext(options);
        }

        private static Instructor SeedInstructor(SchoolContext context,
            string lastName = "Smith", string firstName = "John")
        {
            var instructor = new Instructor
            {
                LastName = lastName,
                FirstMidName = firstName,
                HireDate = DateTime.Parse("2000-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();
            return instructor;
        }

        private static Course SeedCourse(SchoolContext context, int courseId, string title = "Test Course")
        {
            var dept = context.Departments.FirstOrDefault();
            if (dept == null)
            {
                dept = new Department
                {
                    Name = "TestDept",
                    Budget = 100000,
                    StartDate = DateTime.Parse("2007-09-01")
                };
                context.Departments.Add(dept);
                context.SaveChanges();
            }

            var course = new Course
            {
                CourseID = courseId,
                Title = title,
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Courses.Add(course);
            context.SaveChanges();
            return course;
        }

        // 1
        [Fact]
        public void Index_NoParams_ReturnsViewWithInstructors()
        {
            // Arrange
            var context = CreateContext();
            SeedInstructor(context, "Alpha", "A");
            SeedInstructor(context, "Beta", "B");
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Index(null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        // 2
        [Fact]
        public void Index_WithInstructorId_SetsCoursesInViewModel()
        {
            // Arrange
            var context = CreateContext();
            var instructor = SeedInstructor(context);
            var course = SeedCourse(context, 1050, "Chemistry");
            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            });
            context.SaveChanges();

            // Reload to pick up navigation properties
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Index(instructor.ID, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        // 3
        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Arrange
            var context = CreateContext();
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Details(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        // 4
        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            // Arrange
            var context = CreateContext();
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Details(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        // 5
        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            var context = CreateContext();
            var instructor = SeedInstructor(context);
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Details(instructor.ID) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        // 6
        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            // Arrange
            var context = CreateContext();
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Create() as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
        }

        // 7
        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            // Arrange
            var context = CreateContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            // Act
            var result = controller.Create(instructor, null);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Single(context.Instructors);
        }

        // 8
        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            // Arrange
            var context = CreateContext();
            SeedCourse(context, 1050, "Chemistry");
            SeedCourse(context, 4022, "Microeconomics");
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = DateTime.Parse("2020-01-01")
            };

            // Act
            var result = controller.Create(instructor, new[] { "1050", "4022" });

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            var saved = context.Instructors
                .Include(i => i.CourseAssignments)
                .Single();
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        // 9
        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var context = CreateContext();
            var controller = new InstructorsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            // Act
            var result = controller.Create(instructor, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.Empty(context.Instructors);
        }

        // 10
        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Arrange
            var context = CreateContext();
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Edit(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        // 11
        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            var context = CreateContext();
            var instructor = SeedInstructor(context);
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Edit(instructor.ID) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        // 12
        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Arrange
            var context = CreateContext();
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Delete(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        // 13
        [Fact]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            // Arrange
            var context = CreateContext();
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Delete(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        // 14
        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            var context = CreateContext();
            var instructor = SeedInstructor(context);
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Delete(instructor.ID) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        // 15
        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Arrange
            var context = CreateContext();
            var instructor = SeedInstructor(context);
            var controller = new InstructorsController(context);

            // Act
            var result = controller.DeleteConfirmed(instructor.ID);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Empty(context.Instructors);
        }

        // 16
        [Fact]
        public void DeleteConfirmed_ClearsDepartmentInstructorId()
        {
            // Arrange
            var context = CreateContext();
            var instructor = SeedInstructor(context);
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor.ID
            };
            context.Departments.Add(dept);
            context.SaveChanges();
            var controller = new InstructorsController(context);

            // Act
            var result = controller.DeleteConfirmed(instructor.ID);

            // Assert
